const call = $json.call;
const analysis = call.call_analysis ?? {};
const custom = analysis.custom_analysis_data ?? {};

const now = new Date().toISOString();

// Build full name from split fields; fall back to legacy patientName if present
const firstName = custom.patientFirstName ?? '';
const lastName = custom.patientLastName ?? '';
const fullName = [firstName, lastName].filter(Boolean).join(' ') || custom.patientName || 'Unknown (via Ava)';

return [{
  clinicId: call.metadata?.clinicId ?? $env.RETELL_CLINIC_ID,
  patientFirstName: firstName || null,
  patientLastName: lastName || null,
  patientName: fullName,
  patientEmail: custom.patientEmail ?? null,
  patientPhone: custom.patientPhone ?? call.from_number ?? null,
  appointmentType: custom.appointmentType ?? 'initial_assessment',
  appointmentDate: custom.appointmentDate ?? null,
  appointmentTime: custom.appointmentTime ?? null,
  clinicianName: custom.clinicianName ?? null,
  insuranceFlag: custom.insurance_flag ?? false,
  insurerName: custom.insurer ?? null,
  callId: call.call_id,
  callSummary: analysis.call_summary ?? null,
  source: 'strydeos_receptionist',
  createdAt: now,
  updatedAt: now,
}];
